def fix_missing_commas(raw: str) -> str:
    fixed = re.sub(r'(?<=\S) (?=[a-zA-Z_][a-zA-Z0-9_]*=)', ', ', raw)
    return fixed


for model, raw in models.items():
    # Truning strings back to LangChain format
    raw_fixed = fix_missing_commas(raw)
    tree = ast.parse(f"dummy({raw_fixed})")
    call = tree.body[0].value
    kwargs = {}
    for kw in call.keywords:
        kwargs[kw.arg] = ast.literal_eval(kw.value)
    response = AIMessage(**kwargs)

    # Parsing LangChain format
    thinking_models = ["sanitizer", "critic"]
    reasoning_models = ["safeguard_input", "planner", "query_rewriter", "summarizer", "graph_extractor", "reasoner", "answer_generator", "safeguard_output"]
    if model in thinking_models:
        parsed = thinking(response)
        print(f"====== {model} ======")
        print(f"## Thinking\n{parsed.get("thinking")}")
        print(f"## Answer\n{parsed.get("answer")}")
    elif model in reasoning_models:
        parsed = reasoning(response)
        print(f"====== {model} ======")
        print(f"## Thinking\n{parsed.get("thinking")}")
        print(f"## Answer\n{parsed.get("answer")}")
    else:
        parsed = non_thinking(response)
        print(f"====== {model} ======")
        print(f"## Answer\n{parsed.get("answer")}")
    print("\n\n\n")
